  "vulnerabilities": [
    {
      "type": "Authentication Bypass",
      "endpoint": "/index.php",
      "description": "Supplying any 'data' cookie (e.g., 'data=invalid') returns 200 with the authenticated notes page (Welcome header and Add Note form). Without the cookie, /index.php responds 302 to /sign-in.php. Presence of the cookie is treated as authentication without validating contents."
    },
    {
      "type": "Insecure Deserialization (PHP Object Injection)",
      "endpoint": "Cookie: data (set by /sign-in.php, used by /index.php)",
      "description": "After sign-in, the server sets a 'data' cookie containing a base64-encoded PHP serialized object (class UserProfile). Example decoded value: O:11:\"UserProfile\":2:{s:6:\"userid\";i:2;s:8:\"username\";s:...}. Because the server trusts and unserializes client-controlled data, this is likely exploitable for PHP object injection leading to privilege escalation or RCE if a gadget chain exists."
    },
    {
      "type": "Missing Cookie Flags",
      "endpoint": "Set-Cookie headers (/sign-in.php)",
      "description": "Both 'PHPSESSID' and 'data' cookies are set without HttpOnly or Secure attributes, increasing risk of session theft via XSS and interception over plaintext HTTP."
    },
    {
      "type": "CSRF",
      "endpoint": "/index.php (POST /index.php)",
      "description": "The Add Note form posts directly to /index.php without any anti-CSRF token in the HTML. A POST creates/updates content successfully, indicating no CSRF protections and enabling cross-site request forgery."
    }
  ]
}
